import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { IRequestUser } from '@modules/auth/types/auth.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraController } from '@modules/jira/jira.controller';
import { JiraInstallService } from '@modules/jira/jira-install.service';

import type { FastifyReply } from 'fastify';

const mockAdminUser: IRequestUser = {
	user_id: 'user-uuid-1',
	session_id: 'session-1',
	role: 'admin',
	company_id: 'company-uuid-1',
};

const mockJiraInstallService = {
	initiateConnect: jest.fn(),
	handleCallback: jest.fn(),
	disconnect: jest.fn(),
};

const mockConfigService = {
	get: jest.fn().mockReturnValue('http://localhost:3000'),
};

describe('JiraController', () => {
	let controller: JiraController;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			controllers: [JiraController],
			providers: [
				{ provide: JiraInstallService, useValue: mockJiraInstallService },
				{ provide: EnvConfigService, useValue: mockConfigService },
			],
		}).compile();

		controller = module.get<JiraController>(JiraController);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(controller).toBeDefined();
	});

	describe('connect', () => {
		it('should call initiateConnect and return url', async () => {
			const expectedUrl = 'https://auth.atlassian.com/authorize?state=abc';
			mockJiraInstallService.initiateConnect.mockResolvedValue(expectedUrl);

			const result = await controller.connect(mockAdminUser);

			expect(mockJiraInstallService.initiateConnect).toHaveBeenCalledWith({
				companyId: mockAdminUser.company_id,
				userId: mockAdminUser.user_id,
			});
			expect(result).toEqual({ url: expectedUrl });
		});
	});

	describe('callback', () => {
		it('should redirect to success URL on successful callback', async () => {
			mockJiraInstallService.handleCallback.mockResolvedValue(undefined);
			const mockReply = { redirect: jest.fn() };

			await controller.callback(
				{ code: 'auth-code-123', state: 'state-abc' },
				mockReply as unknown as FastifyReply,
			);

			expect(mockJiraInstallService.handleCallback).toHaveBeenCalledWith({
				code: 'auth-code-123',
				state: 'state-abc',
			});
			expect(mockReply.redirect).toHaveBeenCalledWith(
				expect.stringContaining('/settings/integrations?connected=jira'),
				302,
			);
		});

		it('should redirect to error URL when callback throws', async () => {
			mockJiraInstallService.handleCallback.mockRejectedValue(
				new Error('OAuth failed'),
			);
			const mockReply = { redirect: jest.fn() };

			await controller.callback(
				{ code: 'bad-code', state: 'bad-state' },
				mockReply as unknown as FastifyReply,
			);

			expect(mockReply.redirect).toHaveBeenCalledWith(
				expect.stringContaining('/settings/integrations?error=jira_connect_failed'),
				302,
			);
		});
	});

	describe('disconnect', () => {
		it('should call disconnect with correct params', async () => {
			mockJiraInstallService.disconnect.mockResolvedValue(undefined);

			await controller.disconnect(
				{ id: 'install-uuid-1' },
				mockAdminUser,
			);

			expect(mockJiraInstallService.disconnect).toHaveBeenCalledWith({
				installationDbId: 'install-uuid-1',
				companyId: mockAdminUser.company_id,
			});
		});
	});
});

