			mockHttp.axiosRef.get.mockResolvedValue({ data: sprintResponse });

			const result = await service.listSprints({
				cloudId: 'cloud-1',
				token: 'tok',
				boardId: 1,
				startAt: 0,
			});

			expect(mockHttp.axiosRef.get).toHaveBeenCalledWith(
				expect.stringContaining('/board/1/sprint'),
				expect.objectContaining({
					headers: { Authorization: 'Bearer tok' },
					params: { startAt: 0, maxResults: 50 },
				}),
			);
			expect(result).toEqual(sprintResponse);
		});
	});
});

